--
-- Table structure for table `app_collaborator`
--

DROP TABLE IF EXISTS `app_collaborator`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `app_collaborator` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `appId` bigint NOT NULL COMMENT '产物id',
  `userId` bigint NOT NULL COMMENT '协作者用户id',
  `inviterId` bigint NOT NULL COMMENT '邀请人用户id（产物所有者）',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '状态: 0=待确认, 1=已接受, 2=已拒绝, 3=已移除',
  `role` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'editor' COMMENT '协作角色: editor(编辑者), viewer(查看者)',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_app_user` (`appId`,`userId`),
  KEY `idx_userId` (`userId`),
  KEY `idx_appId_status` (`appId`,`status`),
  KEY `idx_userId_status` (`userId`,`status`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='产物协作者表';
/*!40101 SET character_set_client = @saved_cs_client */;

