);\n            position: fixed;\n            top: 0;\n            left: 0;\n            width: 0%;\n            z-index: 9999;\n            transition: width 0.3s ease;\n        }\n\n        .container {\n            max-width: 1200px;\n            margin: 0 auto;\n            padding: 0 20px;\n        }\n\n        /* Header Styles */\n        .header {\n            background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));\n            color: var(--white);\n            padding: 80px 0 60px;\n            text-align: center;\n            position: relative;\n            overflow: hidden;\n        }\n\n        .header::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            bottom: 0;\n            background-image: url(\'https://img1.baidu.com/it/u=3441977137,873658132&fm=253&fmt=auto&app=138&f=JPEG?w=681&h=500\');\n            background-size: cover;\n            background-position: center;\n            opacity: 0.1;\n            z-index: 1;\n        }\n\n        .header-content {\n            position: relative;\n            z-index: 2;\n        }\n\n        .profile-img {\n            width: 150px;\n            height: 150px;\n            border-radius: 50%;\n            border: 4px solid var(--white);\n            object-fit: cover;\n            margin: 0 auto 20px;\n            box-shadow: var(--shadow);\n        }\n\n        .header__title {\n            font-size: 2.5rem;\n            margin-bottom: 10px;\n            font-weight: bold;\n        }\n\n        .header__subtitle {\n            font-size: 1.2rem;\n            margin-bottom: 20px;\n            opacity: 0.9;\n        }\n\n        .header__description {\n            font-size: 1rem;\n            max-width: 600px;\n            margin: 0 auto 30px;\n            opacity: 0.8;\n        }\n\n        .contact-info {\n            display: flex;\n            justify-content: center;\n        