            width: 2px;\n            background: var(--primary-light);\n            transform: translateX(-50%);\n        }\n\n        .timeline-item {\n            position: relative;\n            margin-bottom: 50px;\n            width: calc(50% - 40px);\n        }\n\n        .timeline-item:nth-child(odd) {\n            left: 0;\n        }\n\n        .timeline-item:nth-child(even) {\n            left: calc(50% + 40px);\n        }\n\n        .timeline-card {\n            background: var(--white);\n            padding: 25px;\n            border-radius: var(--border-radius);\n            box-shadow: var(--shadow);\n            transition: var(--transition);\n        }\n\n        .timeline-card:hover {\n            transform: translateY(-5px);\n            box-shadow: 0 8px 25px rgba(0, 0, 0, 0.15);\n        }\n\n        .timeline-date {\n            color: var(--primary-color);\n            font-weight: bold;\n            margin-bottom: 10px;\n            display: block;\n        }\n\n        .timeline-company {\n            font-size: 1.3rem;\n            font-weight: bold;\n            color: var(--text-dark);\n            margin-bottom: 8px;\n        }\n\n        .timeline-position {\n            color: var(--primary-color);\n            font-weight: 600;\n            margin-bottom: 15px;\n            display: block;\n        }\n\n        .timeline-description {\n            color: var(--text-light);\n            line-height: 1.7;\n        }\n\n        .timeline-description ul {\n            padding-left: 20px;\n            margin-top: 10px;\n        }\n\n        .timeline-description li {\n            margin-bottom: 8px;\n        }\n\n        /* Education */\n        .education-cards {\n            display: grid;\n            grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));\n            gap: 30px;\n            max-width: 1000px;\n            margin: 0 auto;\n        }\n\n        .education-card {\n            background: var(--white);\n            padding: 30px;\n            border-radius: var(--border-radius);\n            box-shadow: var(--shadow);\n            text-align: center;\n            transition: var(--transition);\n        }\n\n        .education-card:hover {\n            transform: translateY(-5px);\n            box-shadow: 0 8px 25px rgba(0, 0, 0, 0.15);\n        }\n\n        .education-degree {\n            font-size: 1.4rem;\n            color: var(--primary-color);\n            margin-bottom: 10px;\n        }\n\n        .education-school {\n            font-size: 1.2rem;\n            font-weight: bold;\n            margin-bottom: 10px;\n        }\n\n        .education-year {\n            color: var(--text-light);\n            margin-bottom: 15px;\n        }\n\n        .education-details {\n            text-align: left;\n            color: var(--text-light);\n        }\n\n        .education-details ul {\n            padding-left: 20px;\n        }\n\n        .education-details li {\n            margin-bottom: 5px;\n        }\n\n        /* Skills */\n        .skills-grid {\n            display: grid;\n            grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));\n            gap: 25px;\n            max-width: 1000px;\n            margin: 0 auto;\n        }\n\n        .skill-item {\n            margin-bottom: 20px;\n        }\n\n        .skill-header {\n            display: flex;\n            justify-content: space-between;\n            margin-bottom: 8px;\n        }\n\n        .skill-name {\n            font-weight: 600;\n            color: var(--text-dark);\n        }\n\n        .skill-percent {\n            color: var(--primary-color);\n            font-weight: bold;\n        }\n\n        .skill-bar {\n            height: 10px;\n            background: #e0e0e0;\n            border-radius: 5px;\n            overflow: hidden;\n        }\n\n        .skill-progress {\n            height: 100%;\n            background: linear-gradient(90deg, var(--primary-color), var(--secondary-color));\n 