      }\n\n        /* Achievements Grid */\n        .achievements-grid {\n            display: grid;\n            grid-template-columns: repeat(auto-fit, minmax(350px, 1fr));\n            gap: 25px;\n            margin-top: 20px;\n        }\n\n        .achievement-card {\n            background: white;\n            border-radius: 10px;\n            padding: 25px;\n            box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);\n            border-left: 4px solid var(--primary-color);\n            transition: all 0.3s ease;\n            position: relative;\n            overflow: hidden;\n        }\n\n        .achievement-card:hover {\n            box-shadow: 0 6px 20px rgba(0, 0, 0, 0.1);\n            transform: translateX(5px);\n        }\n\n        .achievement-card::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            height: 3px;\n            background: linear-gradient(90deg, var(--primary-color), var(--secondary-color));\n        }\n\n        .achievement-title {\n            font-size: 1.3rem;\n            color: var(--secondary-color);\n            margin-bottom: 15px;\n            font-weight: 600;\n            display: flex;\n            align-items: center;\n        }\n\n        .achievement-title i {\n            margin-right: 10px;\n            color: var(--primary-color);\n        }\n\n        .achievement-content {\n            font-size: 1.1rem;\n            color: #555;\n            margin-bottom: 15px;\n            line-height: 1.7;\n        }\n\n        .achievement-metric {\n            display: inline-block;\n            background: #e3f2fd;\n            color: #1976d2;\n            padding: 6px 15px;\n            border-radius: 20px;\n            font-weight: 600;\n            font-size: 1.1rem;\n            margin-top: 10px;\n        }\n\n        /* Highlight Box */\n        .highlight {\n            background: linear-gradient(120deg, var(--primary-color), 