DROP TABLE IF EXISTS `chat_message`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `chat_message` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `conversationId` bigint NOT NULL COMMENT '会话id',
  `senderId` bigint NOT NULL COMMENT '发送方用户id',
  `receiverId` bigint NOT NULL COMMENT '接收方用户id',
  `content` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '消息内容',
  `messageType` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'text' COMMENT '消息类型: text=文本, image=图片',
  `isRead` tinyint NOT NULL DEFAULT '0' COMMENT '是否已读: 0=未读, 1=已读',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_conversationId` (`conversationId`),
  KEY `idx_senderId` (`senderId`),
  KEY `idx_receiverId` (`receiverId`),
  KEY `idx_receiverId_isRead` (`receiverId`,`isRead`)
) ENGINE=InnoDB AUTO_INCREMENT=42 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='聊天消息表';
/*!40101 SET character_set_client = @saved_cs_client */;

