--
-- Table structure for table `community_post`
--

DROP TABLE IF EXISTS `community_post`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `community_post` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '帖子id',
  `title` varchar(200) NOT NULL COMMENT '帖子标题',
  `content` text NOT NULL COMMENT '帖子内容',
  `category` varchar(32) NOT NULL DEFAULT 'discuss' COMMENT '分类: discuss(讨论)/question(问答)/feedback(反馈)/share(分享)',
  `userId` bigint NOT NULL COMMENT '发帖用户id',
  `viewCount` int NOT NULL DEFAULT '0' COMMENT '浏览量',
  `likeCount` int NOT NULL DEFAULT '0' COMMENT '点赞量',
  `replyCount` int NOT NULL DEFAULT '0' COMMENT '回复量',
  `isTop` tinyint NOT NULL DEFAULT '0' COMMENT '是否置顶: 0=否, 1=是',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint NOT NULL DEFAULT '0' COMMENT '是否删除: 0=否, 1=是',
  PRIMARY KEY (`id`),
  KEY `idx_category` (`category`),
  KEY `idx_userId` (`userId`),
  KEY `idx_createTime` (`createTime`)
) ENGINE=InnoDB AUTO_INCREMENT=310192815309332483 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='社区帖子表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `community_post`
--

LOCK TABLES `community_post` WRITE;
/*!40000 ALTER TABLE `community_post` DISABLE KEYS */;
INSERT INTO `community_post` VALUES (1,'欢迎来到织码睿奇交流社区！','大家好！这里是织码睿奇的官方交流社区。\n\n你可以在这里：\n- 📢 分享你的使用经验和作品\n- 💡 提出功能建议和需求\n- ❓ 提问并获得社区帮助\n- 🐛 反馈遇到的问题\n\n请大家遵守社区规范，友善交流，共同建设一个良好的技术社区！','discuss',390705603766513664,135,16,3,1,'2026-04-11 18:40:58','2026-04-11 19:03:27',0),(2,'如何用AI生成一个完整的Vue项目？','最近在尝试用平台的AI功能来生成Vue项目，想问下大家有没有什么好的提示词技巧？\n\n我试了几次，发现如果描述得越详细，生成的效果越好。比如说明具体的页面结构、组件划分、数据流向等。\n\n有经验的同学可以分享一下吗？','question',310192815309332480,90,13,2,0,'2026-04-11 18:40:58','2026-04-11 18:56:32',0),(3,'建议增加模板收藏功能','目前平台的模板功能很好用，但是每次都要重新去搜索和选择。\n\n希望能增加一个收藏或\"常用模板\"的功能，这样可以快速选择自己常用的模板来生成代码。\n\n另外如果能支持自定义模板排序就更好了。','feedback',310192815319332482,46,8,1,0,'2026-04-11 18:40:58','2026-04-11 18:53:53',0),(4,'分享：用织码睿奇做的个人博客网站','花了大概20分钟，用平台的AI对话模式做了一个个人博客网站。\n\n使用的是HTML单页模式，包含了首页、文章列表、关于页等。AI还自动帮我加上了响应式布局和暗色模式切换。\n\n感觉对于快速原型或者个人项目来说非常方便，推荐大家试试！','share',310192815309332482,160,22,4,0,'2026-04-11 18:40:58','2026-04-11 18:50:59',0),(5,'代码生成中断后如何恢复？','在生成一个比较复杂的多文件项目时，网络断开了。重新打开页面后发现可以自动恢复继续生成，这个功能真不错！\n\n但想确认一下，断点续传有没有时间限制？另外如果刷新了浏览器缓存还能恢复吗？','question',310192815309332480,36,5,1,0,'2026-04-11 18:40:58','2026-04-11 18:50:57',0),(6,'建议：希望支持MCP工具扩展','看到很多AI平台都开始支持MCP协议了，希望织码睿奇也能支持用户自定义MCP工具。\n\n这样我们就可以接入自己的API、数据库或者第三方服务，让AI在生成代码的时候能获取到更多上下文信息。\n\n不知道官方有没有这方面的计划？','feedback',310192812309332482,69,18,2,0,'2026-04-11 18:40:58','2026-04-11 19:03:35',0),(7,'新手教程：从零开始使用AI生成代码','整理了一份新手入门指南，分享给刚接触平台的同学：\n\n1. 首先进入主页，选择对话模式或应用模式\n2. 在输入框描述你想要生成的内容，越具体越好\n3. 等待AI生成代码，可以实时预览效果\n4. 生成完成后可以下载代码或一键部署\n\n小技巧：使用素材库可以引入现有的设计资源，让生成效果更好！','share',3907056037665136641,204,35,5,0,'2026-04-11 18:40:58','2026-04-11 18:50:34',0),(8,'工作流模式和Agent模式有什么区别？','平台提供了工作流和Agent两种代码生成模式。请问这两种模式的主要区别是什么？分别适合什么样的场景？\n\n我试了一下工作流模式，感觉步骤比较固定。Agent模式好像更灵活，但不太确定什么时候应该用哪个。','question',310192815309332482,91,14,3,0,'2026-04-11 18:40:58','2026-04-11 18:45:38',0);
/*!40000 ALTER TABLE `community_post` ENABLE KEYS */;
UNLOCK TABLES;

