INSERT INTO `customer_service_conversation` VALUES (399794269394653184,'你好，你是谁？',390705603766513664,NULL,'你好！我是小睿，RichCodeWeaver 平台首页右侧的 AI 客服助手 😊  \n我的职责是帮你快速了解平台能力、上手操作、排查常见问题——比如：\n\n✅ 如何生成数字产物（如网页、小程序、API等）  \n✅ 怎么用对话方式创作应用逻辑...','2026-04-09 18:22:13','2026-04-09 18:20:41','2026-04-09 18:20:41',0),(399794666733654016,'我的 AI 产物部署失败了！',390705603766513664,NULL,'你好，我是 RUBY（小睿），看到你的 AI 产物部署失败了，别着急——我们来一步步排查和解决。\n\n✅ **首先确认：部署失败 ≠ 无法修复**  \n平台支持重新部署、查看错误提示、检查前置条件。以下是你可以立即执行的 4 步排查与恢复操作...','2026-04-09 19:51:17','2026-04-09 18:22:16','2026-04-09 18:22:16',0),(399803904222646272,'为什么生成失败了，我应该先检查什么？',390705603766513664,NULL,'RichCodeWeaver 是一个**面向普通用户、聚焦“数字产物”全生命周期的 AI 平台**——它不主打写代码，而是帮你把想法快速变成可看、可用、可分享的数字成果（比如网页、工具页、表单、展示页、简易应用等）。\n\n### ✅ 它的核心...','2026-04-09 19:33:05','2026-04-09 18:58:58','2026-04-09 18:58:58',0),(400092622271668224,'新对话',390705603766513664,NULL,NULL,'2026-04-10 14:06:15','2026-04-10 14:06:14','2026-04-10 14:06:14',0),(400092628684759040,'新对话',390705603766513664,NULL,NULL,'2026-04-10 14:06:16','2026-04-10 14:06:16','2026-04-10 14:06:16',0),(400195758441136128,'新对话',NULL,'guest:c6969038b3914ba8acaf0e828c2e9596',NULL,'2026-04-10 20:56:04','2026-04-10 20:56:04','2026-04-10 20:56:04',0);
