seText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"个体\"}]',1,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(29,'医疗机构官网','enterprise','医疗/健康','医疗机构品牌形象与科室介绍站点','为一家{{identity}}医疗/健康机构创建官方展示静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含机构简介与资质展示、科室导航卡片（含图标和简介）、专家团队（头像+职称+擅长方向）、服务数据量化（接诊量、满意度等数字动效）、就医指南FAQ折叠面板、联系方式区域。{{logoOption}}页面需有滚动渐入动效。所有内容使用真实可信的医疗场景文本。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"医疗蓝(#0277bd+#e1f5fe)\",\"信任绿(#2e7d32+#e8f5e9)\",\"洁净白蓝(#fff+#42a5f5)\",\"温馨暖白(#fafafa+#ff8a65)\"],\"defaultValue\":\"医疗蓝(#0277bd+#e1f5fe)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"经典单页滚动\",\"模块分区卡片\",\"顶部大图+信息区\"],\"defaultValue\":\"经典单页滚动\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为网站设计一个医疗机构风格的SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"企业\"}]',2,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(30,'美食店铺主页','merchant','餐饮/美食','餐饮商户菜品展示与店铺介绍页','为一位{{identity}}餐饮/美食商户创建美食店铺展示静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含店铺招牌Banner（含营业时间）、招牌菜品大图网格（含菜名和价格）、菜品分类标签筛选、门店故事与厨师介绍、顾客好评轮播、门店数据（日均客流、好评率等）。{{logoOption}}页面需有菜品卡片悬浮和图片放大动效。所有内容使用真实可信的餐饮场景数据。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"食欲红(#c62828+#ffebee)\",\"自然棕绿(#33691e+#f1f8e9)\",\"温暖橙黄(#e65100+#fff8e1)\",\"雅致黑红(#212121+#ef5350)\"],\"defaultValue\":\"食欲红(#c62828+#ffebee)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"美食图片网格\",\"菜单列表风格\",\"大图轮播+分区\"],\"defaultValue\":\"美食图片网格\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为网站设计一个美食主题的SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"商户\"}]',1,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(31,'企业财务报表展示','enterprise','金融/财务','企业财务数据可视化与年报展示页','为一家{{identity}}金融/财务企业创建财务数据展示静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含年度业绩总览卡片（营收、利润、增长率等数字动效）、季度趋势图表（纯CSS/SVG柱状图和折线图）、业务板块占比环形图、里程碑时间线、投资者关系FAQ。{{logoOption}}页面需有数据加载和数字滚动动效。所有数据使用真实可信的财务场景数据。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"金融深蓝(#0d47a1+#e3f2fd)\",\"稳重灰金(#37474f+#ffd54f)\",\"专业黑白(#212121+#fafafa)\",\"信任绿(#1b5e20+#e8f5e9)\"],\"defaultValue\":\"金融深蓝(#0d47a1+#e3f2fd)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"数据仪表盘\",\"报告文档风格\",\"卡片分区模块\"],\"defaultValue\":\"数据仪表盘\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为网站设计一个金融专业风格的SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"企业\"}]',1,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(32,'设计师作品集','individual','设计/创意','个人设计作品展示与创意Portfolio','为一位{{identity}}设计/创意从业者创建个人作品集静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含设计师品牌介绍区、作品网格画廊（含项目名称和分类标签，支持筛选）、设计流程时间线、获奖与认证成果区、技能工具图标墙。{{logoOption}}页面需有图片悬浮放大、分类切换和滚动视差动效。所有作品使用纯色占位或CSS渐变代替真实图片。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"极简黑白(#fff+#000)\",\"创意多彩(#f5f5f5+渐变强调色)\",\"温暖米色(#faf8f5+#8d6e63)\",\"高级灰(#eceff1+#455a64)\"],\"defaultValue\":\"极简黑白(#fff+#000)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"网格画廊\",\"全屏滚动\",\"瀑布流\"],\"defaultValue\":\"网格画廊\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为网站设计一个个人品牌风格的SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"个体\"}]',1,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(33,'楼盘展示页','enterprise','房地产/建筑','房地产企业楼盘项目展示页面','为一家{{identity}}房地产/建筑企业创建楼盘展示静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含楼盘全景Banner、户型展示卡片（面积+价格+户型图占位）、小区配套设施图标列表、项目数据量化（总户数、绿化率、车位比等数字动效）、地理位置与周边信息区域、在线预约表单（仅UI无后端）。{{logoOption}}页面需有全屏大图和模块渐入动效。所有内容使用真实可信的房产场景数据。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"高端金灰(#37474f+#ffb74d)\",\"现代白蓝(#fff+#1976d2)\",\"自然绿棕(#2e7d32+#efebe9)\",\"极简黑白(#fff+#212121)\"],\"defaultValue\":\"高端金灰(#37474f+#ffb74d)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"全屏大图+分区\",\"左右分栏\",\"模块卡片网格\"],\"defaultValue\":\"全屏大图+分区\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为网站设计一个房地产品牌风格的SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"企业\"}]',1,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(34,'个人简历页面',NULL,NULL,'制作一个精美的在线个人简历展示页','创建一个{{identity}}的在线个人简历静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含个人照片与基本信息区、工作经历时间线、教育背景、技能评分条（纯CSS动效）、项目经验卡片、联系方式区域。{{logoOption}}页面需有滚动渐入和进度条加载动效。所有内容使用真实可信的示例文本。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"商务蓝(#1565c0+#e3f2fd)\",\"极简黑白(#fff+#1a1a1a)\",\"创意多彩(#f5f5f5+渐变强调色)\",\"暗色高级(#1a1a2e+#e94560)\"],\"defaultValue\":\"商务蓝(#1565c0+#e3f2fd)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"单栏居中\",\"左右分栏\",\"时间线风格\"],\"defaultValue\":\"单栏居中\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":false,\"trueText\":\"请为网站设计一个个人品牌SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"个体\"}]',99,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(35,'活动宣传单页',NULL,NULL,'活动发布与倒计时展示页面','创建一个{{identity}}的活动宣传静态网站。色系：{{colorScheme}}，布局：{{layout}}。包含活动主题全屏Banner、活动倒计时器（纯JS实现实时倒计时）、活动日程时间表、嘉宾/组织者介绍卡片、往期活动数据回顾（参与人数等数字动效）、报名表单（仅UI无后端）。{{logoOption}}页面需有倒计时翻牌和模块渐入动效。所有内容使用真实可信的活动场景文本。','[{\"type\":\"select\",\"key\":\"colorScheme\",\"label\":\"UI色系\",\"options\":[\"活力橙红(#e65100+#fff3e0)\",\"科技蓝紫(#283593+#e8eaf6)\",\"节日金红(#b71c1c+#fff8e1)\",\"清新蓝绿(#00695c+#e0f2f1)\"],\"defaultValue\":\"活力橙红(#e65100+#fff3e0)\"},{\"type\":\"select\",\"key\":\"layout\",\"label\":\"布局建议\",\"options\":[\"全屏模块滚动\",\"经典单页\",\"左右分区\"],\"defaultValue\":\"全屏模块滚动\"},{\"type\":\"switch\",\"key\":\"logoOption\",\"label\":\"是否生成LOGO\",\"defaultValue\":true,\"trueText\":\"请为活动设计一个主题SVG LOGO。\",\"falseText\":\"\"},{\"type\":\"text\",\"key\":\"identity\",\"label\":\"身份描述\",\"defaultValue\":\"个体\"}]',100,1,NULL,'2026-03-20 12:43:37','2026-03-20 12:43:37',0),(392573999994925056,'杜报告','merchant','旅游/酒店','杜报告模板','生成一个网站，颜色为{{color}}','[{\"type\":\"select\",\"key\":\"color\",\"label\":\"UI色系\",\"options\":[\"蓝色\",\"紫色\",\"灰色\"],\"defaultValue\":\"紫色\"}]',0,1,390705603766513664,'2026-03-20 20:09:55','2026-03-20 20:10:14',1);
