LOCK TABLES `rag_param` WRITE;
/*!40000 ALTER TABLE `rag_param` DISABLE KEYS */;
INSERT INTO `rag_param` VALUES (1860000000000001,'max_segment_size','切片最大字符数','500','int','etl','每个文本片段的最大字符数。500 个中文字符约等于 200-300 token，能覆盖一个完整小节。过大检索精度下降，过小丢失上下文。',1,'2026-03-27 19:30:48','2026-03-27 19:30:48'),(1860000000000002,'max_overlap_size','切片重叠字符数','50','int','etl','相邻切片之间的重叠字符数，用于保留跨片段的上下文连续性。约为切片大小的 10%，兼顾上下文保留和存储效率。',2,'2026-03-27 19:30:48','2026-03-27 19:30:48'),(1860000000000003,'max_results','最大检索结果数（Top-K）','5','int','retrieval','每次 RAG 检索返回的最大文档片段数量。过多增加 token 消耗和噪声，过少可能遗漏关键信息。推荐范围：3~10。',3,'2026-03-27 19:30:48','2026-03-27 19:30:48'),(1860000000000004,'min_score','最低相似度阈值','0.6','double','retrieval','检索结果的最低余弦相似度分数（范围 0~1）。低于此值的片段将被过滤，避免注入无关内容。推荐范围：0.5~0.8。',4,'2026-03-27 19:30:48','2026-03-27 19:30:48'),(1860000000000005,'injection_prompt_template','RAG 注入提示词模板','{{userMessage}}\n\n---\n【权威参考知识】以下内容来自系统知识库，是你生成代码时必须严格遵循的开发规范与约束，不可违反或忽略：\n\n{{contents}}\n---','textarea','injection','RAG 内容注入的提示词模板。{{userMessage}} 占位符替换为用户原始消息，{{contents}} 占位符替换为检索到的知识库片段。',5,'2026-03-27 19:30:48','2026-03-27 19:30:48');
/*!40000 ALTER TABLE `rag_param` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `system_prompt`
--

DROP TABLE IF EXISTS `system_prompt`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `system_prompt` (
  `id` bigint NOT NULL COMMENT 'id（雪花）',
  `promptName` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '提示词名称',
  `promptKey` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '提示词唯一标识（如 html-system-prompt）',
  `promptContent` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '提示词内容',
  `description` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '提示词描述',
  `userId` bigint NOT NULL COMMENT '创建人id',
  `createTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `isDelete` tinyint NOT NULL DEFAULT '0' COMMENT '是否删除（逻辑删除）',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='系统提示词';
/*!40101 SET character_set_client = @saved_cs_client */;

